configure.merge_script:
python3 -c "
import json, os
path = os.path.expanduser('~/.openclaw/openclaw.json')
cfg = {}
if os.path.exists(path):
    with open(path) as f: cfg = json.load(f)

# --- fill from '[Attached models for deployment]' block ---
MODEL_ID   = '<attachment model field>'      # e.g. MiniMax-M2.5
MODEL_NAME = '<attachment name field>'       # e.g. MiniMax M2.5
BASE_URL   = '<attachment anthropicUrl if present, else baseUrl>'
API_TYPE   = '<anthropic-messages OR openai-completions>'  # see decision_rule
API_KEY    = '<attachment apiKey>'
CTX        = 128000
MAX_TOK    = 8192
REASONING  = False
# ----------------------------------------------------------

ENV_VAR = 'EB_CUSTOM_API_KEY'
if 'env' not in cfg: cfg['env'] = {}
cfg['env'][ENV_VAR] = API_KEY
if 'models' not in cfg: cfg['models'] = {}
if 'providers' not in cfg['models']: cfg['models']['providers'] = {}
cfg['models']['mode'] = 'merge'
cfg['models']['providers'] = {k:v for k,v in cfg['models']['providers'].items() if not k.startswith('eb_')}
cfg['models']['providers']['eb_custom'] = {'baseUrl': BASE_URL, 'apiKey': '\${EB_CUSTOM_API_KEY}', 'api': API_TYPE, 'models': [{'id': MODEL_ID, 'name': MODEL_NAME, 'reasoning': REASONING, 'input': ['text'], 'cost': {'input': 0, 'output': 0, 'cacheRead': 0, 'cacheWrite': 0}, 'contextWindow': CTX, 'maxTokens': MAX_TOK}]}
if 'agents' not in cfg: cfg['agents'] = {}
if 'defaults' not in cfg['agents']: cfg['agents']['defaults'] = {}
if 'model' not in cfg['agents']['defaults']: cfg['agents']['defaults']['model'] = {}
cfg['agents']['defaults']['model']['primary'] = 'eb_custom/' + MODEL_ID
if 'models' not in cfg['agents']['defaults']['model']: cfg['agents']['defaults']['model']['models'] = {}
cfg['agents']['defaults']['model']['models']['eb_custom/' + MODEL_ID] = {'alias': MODEL_NAME}
with open(path, 'w') as f: json.dump(cfg, f, indent=2)
print('Done:', cfg['agents']['defaults']['model']['primary'])
"
